import React from 'react';
import leftMenuStyles from '../../css/left_menu.module.css'; 

const LeftMenu = ({ activeItem, onMenuItemClick, onLogout }) => {
    
    const menuItems = [
        { label: "Dashboard", icon: "/images/icons/dashboard.svg", alt: "dashboard", key: "dashboard" },
        { label: "Vital Task", icon: "/images/icons/vital_task.svg", alt: "vital task", key: "vital-task" },
        { label: "My Task", icon: "/images/icons/my task.svg", alt: "my task", key: "my-task" },
        { label: "Task Categories", icon: "/images/icons/task_categories.svg", alt: "task categories", key: "categories" },
        { label: "Settings", icon: "/images/icons/settings.svg", alt: "settings", key: "settings" },
        { label: "Help", icon: "/images/icons/help.svg", alt: "help", key: "help" },
    ];

    return (
        <div className={leftMenuStyles.left_menu}>
            
            <div className={leftMenuStyles.profile_eclipse}>
                <img src="/images/profile_image.jpg" alt="profile image" />
            </div>
            
            <h2>Sundar Gurung</h2>
            <h3>sundargurung360@gmail.com</h3>
            
            <div className={leftMenuStyles.left_menu_list}>
                {menuItems.map((item) => {
                    const isActive = activeItem === item.key;
                    
                    const itemClasses = isActive 
                        ? `${leftMenuStyles.left_menu_list_element} ${leftMenuStyles.active}`
                        : leftMenuStyles.left_menu_list_element;
                    
                    return (
                        <div 
                            key={item.key} 
                            className={itemClasses}
                            onClick={() => onMenuItemClick(item.key)}
                        >
                            <div className={leftMenuStyles.icon}>
                                <img src={item.icon} alt={item.alt} />
                            </div>
                            <label>{item.label}</label>
                        </div>
                    );
                })}
            </div>

            <div 
                className={`${leftMenuStyles.logout} ${leftMenuStyles.left_menu_list_element}`} 
                onClick={onLogout}
            >
                <div className={leftMenuStyles.icon}>
                    <img src="../images/icons/logout.svg" alt="logout" />
                </div>
                <label>Logout</label>
            </div>
        </div>
    );
};

export default LeftMenu;
